// ============================================================
// HydraNet - DMAs API Route
// ============================================================

import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'

// GET /api/dmas - List all DMAs (optionally filtered by utility)
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const utilityId = searchParams.get('utilityId')

    const dmas = await prisma.dMA.findMany({
      where: utilityId ? { utilityId } : undefined,
      include: {
        utility: { select: { id: true, name: true } },
        manager: { select: { id: true, name: true, email: true } },
        _count: { select: { branches: true, reports: true, engineers: true } },
      },
      orderBy: [{ utility: { name: 'asc' } }, { name: 'asc' }],
    })

    const formattedDmas = dmas.map((dma) => ({
      ...dma,
      utilityName: dma.utility.name,
      managerName: dma.manager?.name || 'Unassigned',
      branchesCount: dma._count.branches,
      reportsCount: dma._count.reports,
      engineersCount: dma._count.engineers,
    }))

    return NextResponse.json(formattedDmas)
  } catch (error) {
    console.error('Error fetching DMAs:', error)
    return NextResponse.json({ error: 'Failed to fetch DMAs' }, { status: 500 })
  }
}

// POST /api/dmas - Create a new DMA
export async function POST(request: NextRequest) {
  try {
    const data = await request.json()

    // If managerId is provided, update that manager's dmaId
    // Otherwise just create the DMA without a manager
    const dma = await prisma.dMA.create({
      data: {
        name: data.name,
        description: data.description || null,
        utilityId: data.utilityId,
        status: data.status || 'active',
      },
      include: {
        utility: { select: { id: true, name: true } },
        manager: { select: { id: true, name: true } },
        _count: { select: { branches: true, reports: true, engineers: true } },
      },
    })

    // If a manager is assigned, update the manager's dmaId
    if (data.managerId) {
      await prisma.dMAManager.update({
        where: { id: data.managerId },
        data: { dmaId: dma.id },
      })
    }

    // Refetch to get the manager relation
    const updatedDma = await prisma.dMA.findUnique({
      where: { id: dma.id },
      include: {
        utility: { select: { id: true, name: true } },
        manager: { select: { id: true, name: true } },
        _count: { select: { branches: true, reports: true, engineers: true } },
      },
    })

    const formattedDma = {
      ...updatedDma,
      utilityName: updatedDma?.utility.name,
      managerName: updatedDma?.manager?.name || 'Unassigned',
      branchesCount: updatedDma?._count.branches || 0,
      reportsCount: updatedDma?._count.reports || 0,
      engineersCount: updatedDma?._count.engineers || 0,
    }

    return NextResponse.json(formattedDma, { status: 201 })
  } catch (error) {
    console.error('Error creating DMA:', error)
    return NextResponse.json({ error: 'Failed to create DMA' }, { status: 500 })
  }
}